export interface ColVideo {
  youtubeId: string
  source: 'col-collective' | 'tour-de-france' | 'other'
  title?: string
}

export interface Col {
  name: string
  elevation: number
  length?: number
  avgGrade?: number
  maxGrade?: number
  description?: string
  tourAppearances?: number
  firstCrossed?: number
  video?: ColVideo
}

export interface DayStage {
  day: number
  date: string // Format: DD/MM/YYYY
  start: string
  finish: string
  distance: number
  elevation: number
  description: string
  cols: Col[]
  highlights: string[]
  rideWithGPSEmbed?: string
  isTransitDay?: boolean
  coordinates?: {
    start: [number, number]
    end: [number, number]
  }
}

export interface RouteStats {
  totalDistance: number
  totalElevation: number
  totalDays: number
  ridingDays: number
  highestPoint: number
  lowestPoint: number
  startDate: string
  endDate: string
}

